<?php
 namespace WPAICG\Chat\Storage\GetterMethods; use WPAICG\Chat\Storage\BotSettingsManager; if (!defined('ABSPATH')) { exit; } function get_general_bot_settings_logic(int $bot_id, string $bot_name, callable $get_meta_fn): array { $settings = []; if (!class_exists(BotSettingsManager::class)) { $bsm_path = dirname(__DIR__) . '/class-aipkit_bot_settings_manager.php'; if (file_exists($bsm_path)) { require_once $bsm_path; } } $settings['bot_id'] = $bot_id; $settings['name'] = $bot_name; $default_greeting = __('Hello there!', 'gpt3-ai-content-generator'); $default_subgreeting = __('How can I help you today?', 'gpt3-ai-content-generator'); $settings['greeting'] = $get_meta_fn('_aipkit_greeting_message', $default_greeting); $settings['subgreeting'] = $get_meta_fn('_aipkit_subgreeting_message', $default_subgreeting); $default_instructions = __("You are a helpful AI Assistant. Please be friendly. Today's date is [date].", 'gpt3-ai-content-generator'); $settings['instructions'] = $get_meta_fn('_aipkit_instructions', $default_instructions); return $settings; } 